<?phpnamespace App\Http\Controllers;use Illuminate\Http\Request;use App\Http\Controllers\Controller;use App\Models\Community;use App\Models\AgricultureSystemCycle;use App\Models\AgricultureSystem;use App\Models\AgricultureComponent;use App\Models\AgricultureComponentCategory;use App\Models\AgricultureComponentModel;use App\Models\AgricultureSystemComponent;use App\Helpers\SequenceHelper;use Yajra\DataTables\DataTables;use Auth;class AgricultureSystemController extends Controller{    /**     * Display a listing of the resource.     */    public function index(Request $request)    {        // Check if user is authenticated        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        try {            // Get all active agriculture systems with related data            $systems = AgricultureSystem::with(['azollaType', 'agricultureSystemCycle'])                ->where('is_archived', 0)                ->orderBy('created_at', 'desc')                ->get();            return view('system.agriculture.index', compact('systems'));                    } catch (\Exception $e) {            return back()->with('error', 'Error loading agriculture systems: ' . $e->getMessage());        }    }    /**     * Return component categories (AJAX)     */    public function getComponentCategories()    {        $categories = AgricultureComponentCategory::where('is_archived', 0)            ->orderBy('name', 'ASC')            ->get(['id', 'name']);        return response()->json($categories);    }    /**     * Return components by category (AJAX)     */    public function getComponentsByCategory($categoryId)    {        $components = AgricultureComponent::where('agriculture_component_category_id', $categoryId)            ->where('is_archived', 0)            ->orderBy('english_name', 'ASC')            ->get(['id', 'english_name']);        return response()->json($components);    }    /**     * Return models by component (AJAX)     */    public function getModelsByComponent($componentId)    {        $models = AgricultureComponentModel::where('agriculture_component_id', $componentId)            ->where('is_archived', 0)            ->orderBy('model', 'ASC')            ->get(['id', 'model', 'brand', 'unit']);        return response()->json($models);    }    /**     * Show the form for creating a new resource.     */    public function create()    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            return back()->with('error', 'You do not have permission to create agriculture systems.');        }        try {            $communities = Community::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();                            $agricultureSystemCycles = AgricultureSystemCycle::orderBy('name', 'ASC')                ->get();            $azollaTypes = AgricultureComponentModel::where('agriculture_component_id', 5)                ->where('is_archived', 0)                ->orderBy('model', 'ASC')                ->get(['id', 'model as name']);            $components = AgricultureComponent::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();            $componentCategories = AgricultureComponentCategory::where('is_archived', 0)                ->orderBy('name', 'ASC')                ->get();            return view('system.agriculture.create', compact('communities', 'agricultureSystemCycles', 'azollaTypes', 'components', 'componentCategories'));                    } catch (\Exception $e) {            return back()->with('error', 'Error loading form data: ' . $e->getMessage());        }    }    /**     * Store a newly created resource in storage.     */    public function store(Request $request)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            return back()->with('error', 'You do not have permission to create agriculture systems.');        }        $request->validate([            'name' => 'required|string|max:255|unique:agriculture_systems,name',            'azolla_type_id' => 'required|exists:azolla_types,id',            'agriculture_system_cycle_id' => 'nullable|exists:agriculture_system_cycles,id',            'installation_year' => 'nullable|integer|min:1900|max:' . (date('Y') + 10),            'description' => 'nullable|string|max:1000'        ]);        try {            $cometId = SequenceHelper::generateAgricultureSystemCometId();                        AgricultureSystem::create([                'comet_id' => $cometId,                'name' => $request->name,                'azolla_type_id' => $request->azolla_type_id,                'agriculture_system_cycle_id' => $request->agriculture_system_cycle_id,                'installation_year' => $request->installation_year,                'description' => $request->description,                'fake_meter_number' => SequenceHelper::generateAgricultureFakeMeterNumber($cometId),                'is_archived' => 0,            ]);            // Save components if provided (expects JSON array or array of objects)            $componentsData = $request->input('components');            if ($componentsData) {                // If components come as JSON string, decode                if (is_string($componentsData)) {                    $componentsData = json_decode($componentsData, true);                }                if (is_array($componentsData)) {                    // find created system                    $system = AgricultureSystem::where('comet_id', $cometId)->first();                    // detect actual column names in the DB table to avoid unknown column errors                    try {                        $columns = \Schema::getColumnListing('agriculture_system_components');                    } catch (\Exception $e) {                        $columns = [];                    }                    $systemCol = null;                    $componentCol = null;                    $modelCol = null;                    $quantityCol = null;                    $archivedCol = null;                    $unitPriceCol = null;                    $totalPriceCol = null;                    foreach ($columns as $col) {                        $lc = strtolower($col);                        if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                        if (!$componentCol && str_contains($lc, 'component') && str_ends_with($lc, '_id')) $componentCol = $col;                        if (!$modelCol && str_contains($lc, 'model') && str_ends_with($lc, '_id')) $modelCol = $col;                        if (!$quantityCol && ($lc === 'quantity' || str_contains($lc, 'qty'))) $quantityCol = $col;                        if (!$unitPriceCol && (str_contains($lc, 'unit_price') || str_contains($lc, 'unitprice') || str_contains($lc, 'unit'))) $unitPriceCol = $col;                        if (!$totalPriceCol && (str_contains($lc, 'total_price') || str_contains($lc, 'totalprice') || str_contains($lc, 'total'))) $totalPriceCol = $col;                        if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;                    }                    // fallback defaults                    $systemCol = $systemCol ?? 'agriculture_system_id';                    $componentCol = $componentCol ?? 'agriculture_component_id';                    $modelCol = $modelCol ?? 'agriculture_component_model_id';                    $quantityCol = $quantityCol ?? 'quantity';                    $unitPriceCol = $unitPriceCol ?? 'unit_price';                    $totalPriceCol = $totalPriceCol ?? 'total_price';                    $archivedCol = $archivedCol ?? 'is_archived';                    foreach ($componentsData as $c) {                        $row = [                            $systemCol => $system->id,                            $componentCol => $c['component_id'] ?? null,                            $quantityCol => $c['quantity'] ?? 1,                            $unitPriceCol => isset($c['unit_price']) ? $c['unit_price'] : 0,                            $totalPriceCol => (isset($c['unit_price']) ? ($c['unit_price'] * ($c['quantity'] ?? 1)) : 0),                            $archivedCol => 0,                            'created_at' => now(),                            'updated_at' => now(),                        ];                        if (isset($c['model_id'])) {                            $row[$modelCol] = $c['model_id'];                        }                        \DB::table('agriculture_system_components')->insert($row);                    }                }            }            return redirect()->route('agriculture-system.index')                ->with('message', 'Agriculture System created successfully!');                        } catch (\Exception $e) {            return back()->withInput()                ->with('error', 'Error creating agriculture system: ' . $e->getMessage());        }    }    /**     * Display the specified resource.     */    public function show($id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        try {            $system = AgricultureSystem::with(['azollaType', 'agricultureSystemCycle'])->findOrFail($id);            // Build components list for preview in the modal (resilient to column names)            try {                try {                    $columns = \Schema::getColumnListing('agriculture_system_components');                } catch (\Exception $e) {                    $columns = [];                }                $systemCol = null; $componentCol = null; $modelCol = null; $quantityCol = null; $unitPriceCol = null; $totalPriceCol = null; $archivedCol = null;                foreach ($columns as $col) {                    $lc = strtolower($col);                    if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                    if (!$componentCol && str_contains($lc, 'component') && str_ends_with($lc, '_id')) $componentCol = $col;                    if (!$modelCol && str_contains($lc, 'model') && str_ends_with($lc, '_id')) $modelCol = $col;                    if (!$quantityCol && ($lc === 'quantity' || str_contains($lc, 'qty'))) $quantityCol = $col;                    if (!$unitPriceCol && (str_contains($lc, 'unit_price') || str_contains($lc, 'unitprice') || str_contains($lc, 'unit'))) $unitPriceCol = $col;                    if (!$totalPriceCol && (str_contains($lc, 'total_price') || str_contains($lc, 'totalprice') || str_contains($lc, 'total'))) $totalPriceCol = $col;                    if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;                }                $systemCol = $systemCol ?? 'agriculture_system_id';                $componentCol = $componentCol ?? 'agriculture_component_id';                $modelCol = $modelCol ?? 'agriculture_component_model_id';                $quantityCol = $quantityCol ?? 'quantity';                $unitPriceCol = $unitPriceCol ?? 'unit_price';                $totalPriceCol = $totalPriceCol ?? 'total_price';                $archivedCol = $archivedCol ?? 'is_archived';                $query = \DB::table('agriculture_system_components as asc')                    ->leftJoin('agriculture_components as ac', 'ac.id', '=', "asc.{$componentCol}")                    ->leftJoin('agriculture_component_categories as acc', 'acc.id', '=', 'ac.agriculture_component_category_id')                    ->leftJoin('agriculture_component_models as acm', 'acm.id', '=', "asc.{$modelCol}")                    ->where("asc.{$systemCol}", $id)                    ->where("asc.{$archivedCol}", 0)                    ->select([                        "asc.id as id",                        "asc.{$componentCol} as component_id",                        'ac.english_name as component_name',                        'acc.id as category_id',                        'acc.name as category_name',                        "asc.{$modelCol} as model_id",                        "acm.model as model_name",                        "acm.unit as unit",                        "acm.specification as specification",                        "asc.{$quantityCol} as quantity",                        "asc.{$unitPriceCol} as unit_price",                        "asc.{$totalPriceCol} as total_price",                    ]);                $rows = $query->get();                $components = collect($rows)->map(function($r){                        $componentName = strtolower(trim($r->component_name ?? ''));                        $totalPrice = isset($r->total_price) ? floatval($r->total_price) : 0;                        // Exclude certain components from VET. Match common name variants robustly.                        $noVet = false;                        if (str_contains($componentName, 'light-permeable cover') || str_contains($componentName, 'light permeable cover') || str_contains($componentName, 'light-permeable') || str_contains($componentName, 'light permeable')) {                            $noVet = true;                        }                        if ((str_contains($componentName, 'pond') && str_contains($componentName, 'plastic')) || str_contains($componentName, 'plastic pond') || str_contains($componentName, 'pond plastic')) {                            $noVet = true;                        }                        if ($noVet) {                            $totalVet = $totalPrice;                        } else {                            $totalVet = round($totalPrice * 1.16, 2);                        }                    return [                        'id' => $r->id,                        'component_id' => $r->component_id,                        'component_name' => $r->component_name ?? '',                        'category_id' => $r->category_id ?? null,                        'category_name' => $r->category_name ?? '',                        'model_id' => $r->model_id ?? null,                        'model_name' => $r->model_name ?? '',                        'unit' => $r->unit ?? '',                        'specification' => $r->specification ?? '',                        'quantity' => $r->quantity ?? 1,                        'unit_price' => $r->unit_price ?? 0,                        'total_price' => $totalPrice,                        'total_vet' => $totalVet,                    ];                })->values();            } catch (\Exception $e) {                $components = collect();            }            if (request()->ajax()) {                return view('system.agriculture.show-modal', compact('system', 'components'));            }            return view('system.agriculture.show', compact('system', 'components'));                    } catch (\Exception $e) {            if (request()->ajax()) {                return response()->json(['error' => 'System not found'], 404);            }            return back()->with('error', 'Agriculture system not found.');        }    }    /**     * Show the form for editing the specified resource.     */    public function edit($id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            return back()->with('error', 'You do not have permission to edit agriculture systems.');        }        try {            $system = AgricultureSystem::findOrFail($id);                        $communities = Community::where('is_archived', 0)                ->orderBy('english_name', 'ASC')                ->get();                            $agricultureSystemCycles = AgricultureSystemCycle::orderBy('name', 'ASC')                ->get();            $azollaTypes = AzollaType::where('is_archived', 0)                ->orderBy('name', 'ASC')                ->get();            $componentCategories = AgricultureComponentCategory::where('is_archived', 0)                ->orderBy('name', 'ASC')                ->get();            return view('system.agriculture.edit', compact('system', 'communities', 'agricultureSystemCycles', 'azollaTypes', 'componentCategories'));                    } catch (\Exception $e) {            return back()->with('error', 'Agriculture system not found.');        }    }    /**     * Return saved components for a given agriculture system (AJAX)     */    public function getSystemComponents($id)    {        try {            // detect actual column names            try {                $columns = \Schema::getColumnListing('agriculture_system_components');            } catch (\Exception $e) {                $columns = [];            }            $systemCol = null; $componentCol = null; $modelCol = null; $quantityCol = null; $unitPriceCol = null; $totalPriceCol = null; $archivedCol = null;            foreach ($columns as $col) {                $lc = strtolower($col);                if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                if (!$componentCol && str_contains($lc, 'component') && str_ends_with($lc, '_id')) $componentCol = $col;                if (!$modelCol && str_contains($lc, 'model') && str_ends_with($lc, '_id')) $modelCol = $col;                if (!$quantityCol && ($lc === 'quantity' || str_contains($lc, 'qty'))) $quantityCol = $col;                if (!$unitPriceCol && (str_contains($lc, 'unit_price') || str_contains($lc, 'unitprice') || str_contains($lc, 'unit'))) $unitPriceCol = $col;                if (!$totalPriceCol && (str_contains($lc, 'total_price') || str_contains($lc, 'totalprice') || str_contains($lc, 'total'))) $totalPriceCol = $col;                if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;            }            $systemCol = $systemCol ?? 'agriculture_system_id';            $componentCol = $componentCol ?? 'agriculture_component_id';            $modelCol = $modelCol ?? 'agriculture_component_model_id';            $quantityCol = $quantityCol ?? 'quantity';            $unitPriceCol = $unitPriceCol ?? 'unit_price';            $totalPriceCol = $totalPriceCol ?? 'total_price';            $archivedCol = $archivedCol ?? 'is_archived';            // Build query using DB to be resilient to column names            $query = \DB::table('agriculture_system_components as asc')                ->leftJoin('agriculture_components as ac', 'ac.id', '=', "asc.{$componentCol}")                ->leftJoin('agriculture_component_categories as acc', 'acc.id', '=', 'ac.agriculture_component_category_id')                ->leftJoin('agriculture_component_models as acm', 'acm.id', '=', "asc.{$modelCol}")                ->where("asc.{$systemCol}", $id)                ->where("asc.{$archivedCol}", 0)                ->select([                    "asc.id as id",                    "asc.{$componentCol} as component_id",                    'ac.english_name as component_name',                    'acc.id as category_id',                    'acc.name as category_name',                    "asc.{$modelCol} as model_id",                    "acm.model as model_name",                    "asc.{$quantityCol} as quantity",                    "asc.{$unitPriceCol} as unit_price",                    "asc.{$totalPriceCol} as total_price",                ]);            $rows = $query->get();            $data = collect($rows)->map(function($r){                $componentName = strtolower(trim($r->component_name ?? ''));                $totalPrice = isset($r->total_price) ? floatval($r->total_price) : 0;                $noVet = false;                if (str_contains($componentName, 'light-permeable cover') || str_contains($componentName, 'light permeable cover') || str_contains($componentName, 'light-permeable') || str_contains($componentName, 'light permeable')) {                    $noVet = true;                }                if ((str_contains($componentName, 'pond') && str_contains($componentName, 'plastic')) || str_contains($componentName, 'plastic pond') || str_contains($componentName, 'pond plastic')) {                    $noVet = true;                }                if ($noVet) {                    $totalVet = $totalPrice;                } else {                    $totalVet = round($totalPrice * 1.16, 2);                }                return [                    'id' => $r->id,                    'component_id' => $r->component_id,                    'component_name' => $r->component_name ?? '',                    'category_id' => $r->category_id ?? null,                    'category_name' => $r->category_name ?? '',                    'model_id' => $r->model_id ?? null,                    'model_name' => $r->model_name ?? '',                    'quantity' => $r->quantity ?? 1,                    'unit_price' => $r->unit_price ?? 0,                    'total_price' => $totalPrice,                    'total_vet' => $totalVet,                ];            })->values();            return response()->json($data);        } catch (\Exception $e) {            return response()->json([], 500);        }    }    /**     * Update the specified resource in storage.     */    public function update(Request $request, $id)    {        if (!Auth::guard('user')->user()) {            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            return back()->with('error', 'You do not have permission to update agriculture systems.');        }        $request->validate([            'name' => 'required|string|max:255|unique:agriculture_systems,name,' . $id,            'azolla_type_id' => 'required|exists:azolla_types,id',            'agriculture_system_cycle_id' => 'nullable|exists:agriculture_system_cycles,id',            'installation_year' => 'nullable|integer|min:1900|max:' . (date('Y') + 10),            'description' => 'nullable|string|max:1000'        ]);        try {            $system = AgricultureSystem::findOrFail($id);                        $system->update([                'name' => $request->name,                'azolla_type_id' => $request->azolla_type_id,                'agriculture_system_cycle_id' => $request->agriculture_system_cycle_id,                'installation_year' => $request->installation_year,                'description' => $request->description,            ]);            // Update components if provided            $componentsData = $request->input('components');            if ($componentsData) {                if (is_string($componentsData)) {                    $componentsData = json_decode($componentsData, true);                }                if (is_array($componentsData)) {                    // detect columns                    try {                        $columns = \Schema::getColumnListing('agriculture_system_components');                    } catch (\Exception $e) {                        $columns = [];                    }                    $systemCol = null; $componentCol = null; $modelCol = null; $quantityCol = null; $archivedCol = null; $unitPriceCol = null; $totalPriceCol = null;                    foreach ($columns as $col) {                        $lc = strtolower($col);                        if (!$systemCol && str_contains($lc, 'system') && str_ends_with($lc, '_id')) $systemCol = $col;                        if (!$componentCol && str_contains($lc, 'component') && str_ends_with($lc, '_id')) $componentCol = $col;                        if (!$modelCol && str_contains($lc, 'model') && str_ends_with($lc, '_id')) $modelCol = $col;                        if (!$quantityCol && ($lc === 'quantity' || str_contains($lc, 'qty'))) $quantityCol = $col;                        if (!$unitPriceCol && (str_contains($lc, 'unit_price') || str_contains($lc, 'unitprice') || str_contains($lc, 'unit'))) $unitPriceCol = $col;                        if (!$totalPriceCol && (str_contains($lc, 'total_price') || str_contains($lc, 'totalprice') || str_contains($lc, 'total'))) $totalPriceCol = $col;                        if (!$archivedCol && ($lc === 'is_archived' || $lc === 'archived')) $archivedCol = $col;                    }                    $systemCol = $systemCol ?? 'agriculture_system_id';                    $componentCol = $componentCol ?? 'agriculture_component_id';                    $modelCol = $modelCol ?? 'agriculture_component_model_id';                    $quantityCol = $quantityCol ?? 'quantity';                    $unitPriceCol = $unitPriceCol ?? 'unit_price';                    $totalPriceCol = $totalPriceCol ?? 'total_price';                    $archivedCol = $archivedCol ?? 'is_archived';                    // archive existing rows for this system                    try {                        \DB::table('agriculture_system_components')                            ->where($systemCol, $system->id)                            ->update([$archivedCol => 1]);                    } catch (\Exception $e) {                        // ignore                    }                    // insert new components                    foreach ($componentsData as $c) {                        $row = [                            $systemCol => $system->id,                            $componentCol => $c['component_id'] ?? null,                            $quantityCol => $c['quantity'] ?? 1,                            $unitPriceCol => isset($c['unit_price']) ? $c['unit_price'] : 0,                            $totalPriceCol => (isset($c['unit_price']) ? ($c['unit_price'] * ($c['quantity'] ?? 1)) : 0),                            $archivedCol => 0,                            'created_at' => now(),                            'updated_at' => now(),                        ];                        if (isset($c['model_id'])) {                            $row[$modelCol] = $c['model_id'];                        }                        try {                            \DB::table('agriculture_system_components')->insert($row);                        } catch (\Exception $e) {                            // ignore individual insert errors                        }                    }                }            }            return redirect()->route('agriculture-system.index')                ->with('message', 'Agriculture System updated successfully!');                        } catch (\Exception $e) {            return back()->withInput()                ->with('error', 'Error updating agriculture system: ' . $e->getMessage());        }    }    /**     * Remove the specified resource from storage.     */    public function destroy($id)    {        if (!Auth::guard('user')->user()) {            if (request()->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);            }            return redirect()->route('login')->with('error', 'Please login to access this page.');        }        // Check user permissions        $userType = Auth::guard('user')->user()->user_type_id;        if (!in_array($userType, [1, 2, 14, 15])) {            if (request()->ajax()) {                return response()->json(['success' => false, 'message' => 'Unauthorized'], 403);            }            return back()->with('error', 'You do not have permission to delete agriculture systems.');        }        try {            $system = AgricultureSystem::findOrFail($id);                        // Soft delete by archiving            $system->update(['is_archived' => 1]);                        if (request()->ajax()) {                return response()->json([                    'success' => true,                     'message' => 'Agriculture System deleted successfully!'                ]);            }                        return redirect()->route('agriculture-system.index')                ->with('message', 'Agriculture System deleted successfully!');                        } catch (\Exception $e) {            if (request()->ajax()) {                return response()->json([                    'success' => false,                     'message' => 'Error deleting system: ' . $e->getMessage()                ], 500);            }                        return back()->with('error', 'Error deleting Agriculture System!');        }    }}